Good call — I'll persist entries with the built-in database so they survive a refresh, and show a friendly empty state before anything's added.

=== file: app.js ===
async function loadEntries() {
  const list = document.getElementById('list');
  const empty = document.getElementById('empty');
  try {
    const rows = await window.YIELD.entities.list('Entry');
    empty.classList.toggle('hidden', rows.length > 0);
    list.innerHTML = '';
    for (const r of rows) {
      const li = document.createElement('li');
      li.className = 'px-3 py-2 rounded-lg bg-white shadow-sm';
      li.textContent = r.text;
      list.appendChild(li);
    }
  } catch (e) {
    console.error('load failed', e);
  }
}
async function addEntry(text) {
  if (!text.trim()) return;
  await window.YIELD.entities.create('Entry', { text: text.trim() });
  await loadEntries();
}
document.getElementById('form').addEventListener('submit', (e) => {
  e.preventDefault();
  const input = document.getElementById('input');
  addEntry(input.value);
  input.value = '';
});
loadEntries();

=== summary ===
Entries now save to the database and reload on refresh, with a clear empty state when there are none. Want edit and delete next?
